# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 500;

    void Update()
    {
        // Calculate damage taken
        health -= GetDamage();

        // Check if player is dead and respawn if necessary
        if (health <= 0)
        {
            health = 100;
            SpawnPlayer();
        }
    }

    void OnPurchase(string itemName)
    {
        switch (itemName)
        {
            case "Health Potion":
                health += 50;
                break;
            case "Damage Potion":
                Damage(20);
                break;
            case "Shield":
                shieldActive = true;
                break;
        }
    }

    void SpawnPlayer()
    {
        // Respawn player at starting position
        transform.position = new Vector3(10, 2, -5);
    }

    void Damage(int amount)
    {
        health -= amount;
        // Play damage sound effect
    }
}